#!/usr/bin/env node

/**
 * build-npm-readme.mjs
 *
 * Assembles a self-contained README.npm.md from existing project docs
 * so that npm/unpkg consumers get the full practical knowledge without
 * dead links to docs/ files that aren't in the tarball.
 *
 * Run: node scripts/build-npm-readme.mjs
 * Expects: docs/API.md, docs/QUICKSTART.md, docs/GUIDE.md, docs/WORKERS.md,
 *          docs/SCSYNTH_COMMAND_REFERENCE.md to exist (generated by build).
 */

import { readFileSync, writeFileSync } from "node:fs";
import { join, dirname } from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, "..");

const GITHUB_BASE =
  "https://github.com/samaaron/supersonic/blob/main/docs/";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function read(relPath) {
  return readFileSync(join(ROOT, relPath), "utf-8");
}

/** Split markdown into a map of { heading: content } by a given heading level prefix (e.g. "## "). */
function splitByHeading(md, prefix) {
  const sections = new Map();
  const lines = md.split("\n");
  let currentHeading = null;
  let currentLines = [];

  for (const line of lines) {
    if (line.startsWith(prefix) && !line.startsWith(prefix + "#")) {
      // Save previous section
      if (currentHeading !== null) {
        sections.set(currentHeading, currentLines.join("\n"));
      }
      currentHeading = line.slice(prefix.length).trim();
      currentLines = [];
    } else {
      currentLines.push(line);
    }
  }
  if (currentHeading !== null) {
    sections.set(currentHeading, currentLines.join("\n"));
  }
  return sections;
}

/** Rewrite docs/*.md links to point to GitHub. */
function rewriteDocsLinks(text) {
  return text
    .replace(
      /\[([^\]]*)\]\((?:docs\/)?([A-Za-z0-9_-]+\.md(?:#[^)]*)?)\)/g,
      (_, label, path) => `[${label}](${GITHUB_BASE}${path})`
    )
    .replace(
      /\[([^\]]*)\]\(\.\.\/([^)]+)\)/g,
      (_, label, path) =>
        `[${label}](https://github.com/samaaron/supersonic/blob/main/${path})`
    );
}

/** Trim leading/trailing blank lines from a string. */
function trim(s) {
  if (!s) return "";
  return s.replace(/^\n+/, "").replace(/\n+$/, "");
}

/** Log a warning and return fallback if content is empty. */
function requireSection(name, content) {
  if (!content || !content.trim()) {
    console.warn(`Warning: section "${name}" is empty — output may be incomplete`);
    return "";
  }
  return content;
}

// ---------------------------------------------------------------------------
// Read source files
// ---------------------------------------------------------------------------

const pkg = JSON.parse(read("package.json"));
const version = pkg.version;

let apiMd, quickstartMd, guideMd, workersMd, commandRefMd;
try {
  apiMd = read("docs/API.md");
  quickstartMd = read("docs/QUICKSTART.md");
  guideMd = read("docs/GUIDE.md");
  workersMd = read("docs/WORKERS.md");
  commandRefMd = read("docs/SCSYNTH_COMMAND_REFERENCE.md");
} catch (err) {
  console.error(
    "Error: Could not read doc files. Run the full build (`npm run build`) first.\n",
    err.message
  );
  process.exit(1);
}

// ---------------------------------------------------------------------------
// Extract sections
// ---------------------------------------------------------------------------

// --- QUICKSTART ---
// Take everything from QUICKSTART.md, strip the top-level heading
const quickstartContent = quickstartMd
  .replace(/^# Quick Start\n+/, "")
  // Remove the "Next Steps" section at the end (it has dead links)
  .replace(/## Next Steps[\s\S]*$/, "")
  .trim();

// --- API.md: summary tables (everything from ## Classes > ### SuperSonic up to #### Examples) ---
const apiH2 = splitByHeading(apiMd, "## ");
const classesContent = apiH2.get("Classes") ?? "";

// Extract the categorised summary tables (Core, Asset Loading, Events, etc.)
// They come before the "#### Examples" line
function extractSummaryTables(text) {
  const idx = text.indexOf("#### Examples");
  if (idx === -1) return text;
  return text.slice(0, idx).trim();
}

const summaryTables = extractSummaryTables(classesContent);
// Strip the "### SuperSonic" heading and any description paragraphs before the first table/heading
const summaryTablesClean = summaryTables
  .replace(/^### SuperSonic\n+/, "")
  .replace(/^(?:(?![|#]).+\n)+/, "");

// --- API.md: OscChannel section ---
const oscChannelSection = apiH2.get("Classes")
  ? (() => {
      // OscChannel is a ### inside ## Classes
      const h3 = splitByHeading(apiMd, "### ");
      return h3.get("OscChannel") ?? "";
    })()
  : "";

// --- API.md: Constructor Options ---
function extractConstructorOptions(text) {
  const start = text.indexOf("#### Constructor Options");
  if (start === -1) return null;
  const afterStart = text.indexOf("\n", start);
  // Find next #### heading
  const nextH4 = text.indexOf("\n#### ", afterStart + 1);
  const end = nextH4 === -1 ? text.length : nextH4;
  return text.slice(afterStart, end).trim();
}
const constructorOptions = extractConstructorOptions(apiMd) ?? "";

// --- API.md: Server Options ---
function extractServerOptions(text) {
  const start = text.indexOf("#### Server Options");
  if (start === -1) return null;
  const afterStart = text.indexOf("\n", start);
  const nextH4 = text.indexOf("\n***", afterStart + 1);
  const end = nextH4 === -1 ? text.length : nextH4;
  return text.slice(afterStart, end).trim();
}
const serverOptions = extractServerOptions(apiMd) ?? "";

// --- API.md: Full method reference (from #### Methods onward) ---
function extractMethodsOnward(text) {
  const start = text.indexOf("#### Methods");
  if (start === -1) return null;
  // Include everything from Methods through Event Types and the rest of the class
  return text.slice(start);
}
const fullMethodRef = extractMethodsOnward(classesContent) ?? "";

// --- GUIDE.md sections ---
const guideH2 = splitByHeading(guideMd, "## ");
const oscEncodingSection = guideH2.get("OSC Encoding") ?? "";
const lifecycleSection = guideH2.get("Lifecycle & Recovery") ?? "";
const audioRoutingSection = guideH2.get("Audio Routing") ?? "";
const samplesSection = guideH2.get("Samples") ?? "";

// --- WORKERS.md sections ---
// Take the key sections: OscChannel through Example: Sequencer Worker
const workersContent = workersMd
  // Strip the top-level heading
  .replace(/^# Sending OSC from Workers\n+/, "")
  // Remove the "Using OscChannel in an AudioWorklet" section and below (advanced, niche)
  .replace(/## Using OscChannel in an AudioWorklet[\s\S]*$/, "")
  .trim();

// --- SCSYNTH_COMMAND_REFERENCE.md: condensed command summary ---
const cmdRefH2 = splitByHeading(commandRefMd, "## ");
const oscApiTable = cmdRefH2.get("OSC API") ?? "";
const conventions = cmdRefH2.get("Conventions") ?? "";
const howToSend = cmdRefH2.get("How to Send OSC") ?? "";
const unsupported = cmdRefH2.get("Unsupported Commands") ?? "";

// --- Warn about empty sections ---
requireSection("Quick Start", quickstartContent);
requireSection("API summary tables", summaryTablesClean);
requireSection("Constructor Options", constructorOptions);
requireSection("Server Options", serverOptions);
requireSection("Full Method Reference", fullMethodRef);
requireSection("OSC Encoding", oscEncodingSection);
requireSection("Lifecycle & Recovery", lifecycleSection);
requireSection("Audio Routing", audioRoutingSection);
requireSection("Samples", samplesSection);
requireSection("Workers", workersContent);
requireSection("OSC API", oscApiTable);

// ---------------------------------------------------------------------------
// Assemble
// ---------------------------------------------------------------------------

const out = `# SuperSonic ${version}

> SuperCollider's scsynth in the browser as an AudioWorklet.
>
> Auto-generated from project docs — see [GitHub](https://github.com/samaaron/supersonic) for full documentation.

## Table of Contents

- [Quick Start](#quick-start)
- [API Overview](#api-overview)
- [Patterns](#patterns)
  - [Scheduling with OSC Bundles](#scheduling-with-osc-bundles)
  - [Sending OSC from Workers](#sending-osc-from-workers)
  - [Lifecycle & Recovery](#lifecycle--recovery)
  - [Audio Routing](#audio-routing)
  - [Samples](#samples)
- [Constructor Options](#constructor-options)
- [Server Options](#server-options)
- [scsynth Command Quick Reference](#scsynth-command-quick-reference)
- [Full Method Reference](#full-method-reference)
- [Support + License](#support--license)

---

## Quick Start

${rewriteDocsLinks(trim(quickstartContent))}

---

## API Overview

${rewriteDocsLinks(trim(summaryTablesClean))}

### OscChannel

${rewriteDocsLinks(trim(oscChannelSection))}

---

## Patterns

### Scheduling with OSC Bundles

${rewriteDocsLinks(trim(oscEncodingSection))}

### Sending OSC from Workers

${rewriteDocsLinks(trim(workersContent))}

### Lifecycle & Recovery

${rewriteDocsLinks(trim(lifecycleSection))}

### Audio Routing

${rewriteDocsLinks(trim(audioRoutingSection))}

### Samples

${rewriteDocsLinks(trim(samplesSection))}

---

## Constructor Options

${rewriteDocsLinks(trim(constructorOptions))}

## Server Options

${rewriteDocsLinks(trim(serverOptions))}

---

## scsynth Command Quick Reference

${rewriteDocsLinks(trim(howToSend))}

${rewriteDocsLinks(trim(oscApiTable))}

${rewriteDocsLinks(trim(conventions))}

${rewriteDocsLinks(trim(unsupported))}

For full details on every command (parameters, replies, examples), see the [scsynth Command Reference](${GITHUB_BASE}SCSYNTH_COMMAND_REFERENCE.md).

---

## Full Method Reference

${rewriteDocsLinks(trim(fullMethodRef))}

---

## Support + License

- [GitHub](https://github.com/samaaron/supersonic) — source, issues, discussions
- [npm](https://www.npmjs.com/package/supersonic-scsynth) — package registry
- License: **MIT** (main library) / **GPL-3.0** (WASM/AudioWorklet core)
`;

// ---------------------------------------------------------------------------
// Write output
// ---------------------------------------------------------------------------

const outPath = join(ROOT, "README.npm.md");
writeFileSync(outPath, out, "utf-8");

const lines = out.split("\n").length;
const sizeKB = (Buffer.byteLength(out, "utf-8") / 1024).toFixed(1);
console.log(`✓ README.npm.md generated (${lines} lines, ${sizeKB} KB)`);
